create or replace function public.lf_acknowledge_alert(
    p_alert_key text,
    p_actor_id text default 'default-admin',
    p_note text default null
)
returns boolean
language plpgsql
as $$
begin
    insert into public.alert_acknowledgements (
        alert_key,
        actor_id,
        note
    )
    values (
        p_alert_key,
        p_actor_id,
        p_note
    )
    on conflict (alert_key, actor_id) do update
    set
        acknowledged_at = now(),
        note = excluded.note;

    return true;
