-- =====================================================================
-- FILE: 13_dashboard_views.sql
-- =====================================================================

-- Read-only views matching the current dashboard pages.

begin;

create or replace view public.lf_v_backend_status as
select
    b.id,
    b.name,
    b.url,
    b.weight,
    b.enabled,
    s.status,
    s.active_requests,
    s.total_requests,
    s.total_errors,
    s.last_latency_ms,
    s.last_checked_at,
    s.last_error,
    s.consecutive_successes,
    s.consecutive_failures,
    case
        when b.enabled
         and s.status in ('healthy', 'unknown')
        then true
        else false
    end as eligible,
    case
        when s.total_requests = 0 then 0::numeric
        else round(
            s.total_errors::numeric / s.total_requests::numeric * 100,
            2
        )
    end as error_rate,
    b.created_at,
    b.updated_at
from public.backend_services b
join public.backend_runtime_state s
  on s.backend_id = b.id
where b.deleted_at is null;


create or replace view public.lf_v_recent_request_logs as
select
    r.request_id,
    r.completed_at as timestamp,
    r.http_method as method,
    r.route as path,
    r.final_backend_id as backend_id,
    r.final_status_code as status_code,
    r.total_duration_ms as duration_ms,
    r.error_message as error,
    r.retry_count
from public.api_request_history r;


create or replace view public.lf_v_request_overview_24h as
with scoped as (
    select *
    from public.api_request_history
    where received_at >= now() - interval '24 hours'
),
duration_stats as (
    select
        count(*)::bigint as total_requests,
        coalesce(avg(total_duration_ms), 0)::numeric as average_latency_ms,
        coalesce(
            percentile_cont(0.95) within group (
                order by total_duration_ms
            ),
            0
        )::numeric as p95_latency_ms,
        coalesce(
            percentile_cont(0.99) within group (
                order by total_duration_ms
            ),
            0
        )::numeric as p99_latency_ms,
        count(*) filter (
            where final_status_code >= 500
               or error_type is not null
        )::bigint as error_count,
        min(received_at) as first_received_at,
        max(completed_at) as last_completed_at
    from scoped
)
select
    total_requests,
    round(
        total_requests::numeric
        / greatest(
            extract(
                epoch from (
                    coalesce(last_completed_at, now())
                    - coalesce(first_received_at, now())
                )
            ),
            1
        ),
        2
    ) as requests_per_second,
    round(average_latency_ms, 2) as average_latency_ms,
    round(p95_latency_ms, 2) as p95_latency_ms,
    round(p99_latency_ms, 2) as p99_latency_ms,
    round(
        case
            when total_requests = 0 then 0
            else error_count::numeric / total_requests::numeric * 100
        end,
        2
    ) as error_rate
from duration_stats;


create or replace view public.lf_v_endpoint_analytics_24h as
select
    route as path,
    count(*)::bigint as requests,
    round(avg(total_duration_ms), 2) as average_latency_ms,
    round(
        percentile_cont(0.95) within group (
            order by total_duration_ms
        )::numeric,
        2
    ) as p95_latency_ms,
    round(
        percentile_cont(0.99) within group (
            order by total_duration_ms
        )::numeric,
        2
    ) as p99_latency_ms,
    round(
        count(*) filter (
            where final_status_code >= 500
               or error_type is not null
        )::numeric
        / greatest(count(*)::numeric, 1)
        * 100,
        2
    ) as error_rate
from public.api_request_history
where received_at >= now() - interval '24 hours'
group by route;


create or replace view public.lf_v_backend_distribution_24h as
select
    coalesce(final_backend_id, 'none') as backend_id,
    count(*)::bigint as request_count,
    round(
        count(*)::numeric
        / greatest(
            sum(count(*)) over (),
            1
        )::numeric
        * 100,
        2
    ) as traffic_share_percent
from public.api_request_history
where received_at >= now() - interval '24 hours'
group by coalesce(final_backend_id, 'none');


create or replace view public.lf_v_request_timeseries_15s as
select
    to_timestamp(
        floor(extract(epoch from received_at) / 15) * 15
    ) as bucket_start,
    count(*)::bigint as requests,
    count(*) filter (
        where final_status_code >= 500
           or error_type is not null
    )::bigint as errors,
    round(avg(total_duration_ms), 2) as average_latency_ms
from public.api_request_history
group by 1;


create or replace view public.lf_v_security_summary_24h as
select
    count(distinct client_ip) filter (
        where blocked = true
    )::bigint as blocked_ips_count,
    count(*) filter (
        where event_type = 'rate_limit_exceeded'
    )::bigint as rate_limit_hits,
    count(*) filter (
        where event_type = 'auth_failure'
    )::bigint as auth_failures,
    count(*) filter (
        where event_type in (
            'suspicious_request',
            'sql_injection_detected',
            'suspicious_user_agent'
        )
    )::bigint as suspicious_events
from public.security_events
where occurred_at >= now() - interval '24 hours';


create or replace view public.lf_v_load_test_history as
select
    id,
    external_id,
    name,
    target_path,
    status,
    duration_seconds,
    concurrency,
    selected_algorithm,
    started_at,
    completed_at,
    progress,
    throughput_rps,
    average_latency_ms,
    p50_latency_ms,
    p95_latency_ms,
    p99_latency_ms,
    error_rate,
    success_count,
    error_count,
    total_requests,
    created_at
from public.load_test_runs;


create or replace view public.lf_v_latest_db_pool_samples as
select distinct on (instance_id)
    instance_id,
    sampled_at,
    configured_pool_size,
    checked_in_connections,
    checked_out_connections,
    overflow_connections,
    acquisition_wait_ms,
    timeout_count,
    connection_error_count,
    metadata
from public.db_pool_samples
order by instance_id, sampled_at desc;

commit;

-- =====================================================================
-- FILE: 14_alert_and_retention_functions.sql
-- =====================================================================

-- Active alerts and configurable cleanup functions.

begin;

create or replace function public.lf_get_active_alerts(
    p_actor_id text default 'default-admin',
    p_limit integer default 100
)
returns table (
    alert_key text,
    title text,
    source text,
    level text,
    occurred_at timestamptz,
    metadata jsonb
)
language sql
stable
as $$
with candidate_alerts as (
    select
        'backend-status-' || b.id || '-' || s.status as alert_key,
        case
            when s.status = 'unhealthy'
                then 'Health check failed for ' || b.name
            when s.status = 'draining'
                then 'Traffic draining enabled for ' || b.name
            when s.status = 'disabled'
                then 'Backend ' || b.name || ' has been disabled'
            else 'Backend state changed for ' || b.name
        end as title,
        'Backend: ' || b.id as source,
        case
            when s.status = 'unhealthy' then 'Critical'
            else 'Warning'
        end as level,
        coalesce(s.last_checked_at, s.updated_at) as occurred_at,
        jsonb_build_object(
            'backend_id', b.id,
            'status', s.status,
            'last_error', s.last_error
        ) as metadata
    from public.backend_services b
    join public.backend_runtime_state s
      on s.backend_id = b.id
    where b.deleted_at is null
      and s.status in ('unhealthy', 'draining', 'disabled')

    union all

    select
        'request-error-' || r.request_id,
        case
            when r.error_message is not null
                then 'Proxy error: ' || r.error_message
            else 'HTTP ' || r.final_status_code::text
                 || ' on ' || r.http_method || ' ' || r.route
        end,
        'Request ID: ' || r.request_id,
        case
            when r.final_status_code >= 500
              or r.error_type is not null
                then 'Critical'
            else 'Warning'
        end,
        r.completed_at,
        jsonb_build_object(
            'request_id', r.request_id,
            'status_code', r.final_status_code,
            'backend_id', r.final_backend_id,
            'error_type', r.error_type
        )
    from public.api_request_history r
    where r.completed_at >= now() - interval '24 hours'
      and (
          r.final_status_code >= 400
          or r.error_type is not null
      )

    union all

    select
        'security-' || e.id::text,
        e.title,
        coalesce(e.client_ip::text, 'Security monitor'),
        case
            when e.severity in ('error', 'critical')
                then 'Critical'
            else 'Warning'
        end,
        e.occurred_at,
        jsonb_build_object(
            'event_type', e.event_type,
            'client_ip', e.client_ip,
            'request_id', e.request_id
        )
    from public.security_events e
    where e.occurred_at >= now() - interval '24 hours'
      and e.severity in ('warning', 'error', 'critical')
)
select
    c.alert_key,
    c.title,
    c.source,
    c.level,
    c.occurred_at,
    c.metadata
from candidate_alerts c
left join public.alert_acknowledgements a
  on a.alert_key = c.alert_key
 and a.actor_id = p_actor_id
where a.alert_key is null
order by c.occurred_at desc
limit greatest(least(p_limit, 500), 1);
$$;


create or replace function public.lf_cleanup_expired_data(
    p_request_retention_days integer default 30,
    p_health_retention_days integer default 14,
    p_system_log_retention_days integer default 30,
    p_security_retention_days integer default 90,
    p_worker_retention_days integer default 7,
    p_pool_sample_retention_days integer default 14
)
returns jsonb
language plpgsql
as $$
declare
    v_requests bigint;
    v_health bigint;
    v_logs bigint;
    v_security bigint;
    v_workers bigint;
    v_pool bigint;
begin
    delete from public.api_request_history
    where received_at
        < now() - make_interval(days => p_request_retention_days);
    get diagnostics v_requests = row_count;

    delete from public.backend_health_checks
    where checked_at
        < now() - make_interval(days => p_health_retention_days);
    get diagnostics v_health = row_count;

    delete from public.system_logs
    where occurred_at
        < now() - make_interval(days => p_system_log_retention_days);
    get diagnostics v_logs = row_count;

    delete from public.security_events
    where occurred_at
        < now() - make_interval(days => p_security_retention_days);
    get diagnostics v_security = row_count;

    delete from public.api_ingest_jobs
    where status in ('completed', 'failed', 'discarded')
      and coalesce(completed_at, updated_at)
        < now() - make_interval(days => p_worker_retention_days);
    get diagnostics v_workers = row_count;

    delete from public.db_pool_samples
    where sampled_at
        < now() - make_interval(days => p_pool_sample_retention_days);
    get diagnostics v_pool = row_count;

    return jsonb_build_object(
        'api_requests_deleted', v_requests,
        'health_checks_deleted', v_health,
        'system_logs_deleted', v_logs,
        'security_events_deleted', v_security,
        'worker_jobs_deleted', v_workers,
        'pool_samples_deleted', v_pool
    );
end;
$$;

commit;

-- =====================================================================
-- FILE: 15_rls_and_permissions.sql
-- =====================================================================

-- Backend-only access model.
--
-- anon/authenticated are intentionally blocked.
-- Direct PostgreSQL connections using the database owner continue to work.
-- Supabase service_role may be used only from trusted backend infrastructure.

begin;

alter table public.backend_services enable row level security;
alter table public.backend_runtime_state enable row level security;
alter table public.backend_state_events enable row level security;
alter table public.routing_configuration enable row level security;
alter table public.routing_configuration_history enable row level security;
alter table public.platform_settings enable row level security;
alter table public.load_test_runs enable row level security;
alter table public.load_test_samples enable row level security;
alter table public.load_test_backend_results enable row level security;
alter table public.api_ingest_jobs enable row level security;
alter table public.api_request_history enable row level security;
alter table public.api_request_attempts enable row level security;
alter table public.backend_health_checks enable row level security;
alter table public.security_events enable row level security;
alter table public.security_ip_counters enable row level security;
alter table public.system_logs enable row level security;
alter table public.audit_events enable row level security;
alter table public.alert_acknowledgements enable row level security;
alter table public.db_pool_samples enable row level security;

revoke all on table public.backend_services
    from anon, authenticated;
revoke all on table public.backend_runtime_state
    from anon, authenticated;
revoke all on table public.backend_state_events
    from anon, authenticated;
revoke all on table public.routing_configuration
    from anon, authenticated;
revoke all on table public.routing_configuration_history
    from anon, authenticated;
revoke all on table public.platform_settings
    from anon, authenticated;
revoke all on table public.load_test_runs
    from anon, authenticated;
revoke all on table public.load_test_samples
    from anon, authenticated;
revoke all on table public.load_test_backend_results
    from anon, authenticated;
revoke all on table public.api_ingest_jobs
    from anon, authenticated;
revoke all on table public.api_request_history
    from anon, authenticated;
revoke all on table public.api_request_attempts
    from anon, authenticated;
revoke all on table public.backend_health_checks
    from anon, authenticated;
revoke all on table public.security_events
    from anon, authenticated;
revoke all on table public.security_ip_counters
    from anon, authenticated;
revoke all on table public.system_logs
    from anon, authenticated;
revoke all on table public.audit_events
    from anon, authenticated;
revoke all on table public.alert_acknowledgements
    from anon, authenticated;
revoke all on table public.db_pool_samples
    from anon, authenticated;

revoke all on table public.lf_v_backend_status
    from anon, authenticated;
revoke all on table public.lf_v_recent_request_logs
    from anon, authenticated;
revoke all on table public.lf_v_request_overview_24h
    from anon, authenticated;
revoke all on table public.lf_v_endpoint_analytics_24h
    from anon, authenticated;
revoke all on table public.lf_v_backend_distribution_24h
    from anon, authenticated;
revoke all on table public.lf_v_request_timeseries_15s
    from anon, authenticated;
revoke all on table public.lf_v_security_summary_24h
    from anon, authenticated;
revoke all on table public.lf_v_load_test_history
    from anon, authenticated;
revoke all on table public.lf_v_latest_db_pool_samples
    from anon, authenticated;

-- PostgreSQL grants EXECUTE on new functions to PUBLIC by default.
-- Revoke only LoadFlow functions, identified by the lf_ prefix.
do $$
declare
    item record;
begin
    for item in
        select
            p.oid::regprocedure as function_signature
        from pg_proc p
        join pg_namespace n
          on n.oid = p.pronamespace
        where n.nspname = 'public'
          and p.proname like 'lf\_%' escape '\'
    loop
        execute format(
            'revoke all on function %s from public, anon, authenticated',
            item.function_signature
        );
    end loop;
end;
$$;

-- Optional trusted-server access through the Supabase service role.
grant select, insert, update, delete
    on public.backend_services,
       public.backend_runtime_state,
       public.backend_state_events,
       public.routing_configuration,
       public.routing_configuration_history,
       public.platform_settings,
       public.load_test_runs,
       public.load_test_samples,
       public.load_test_backend_results,
       public.api_ingest_jobs,
       public.api_request_history,
       public.api_request_attempts,
       public.backend_health_checks,
       public.security_events,
       public.security_ip_counters,
       public.system_logs,
       public.audit_events,
       public.alert_acknowledgements,
       public.db_pool_samples
    to service_role;

grant usage, select
    on all sequences in schema public
    to service_role;

grant select
    on public.lf_v_backend_status,
       public.lf_v_recent_request_logs,
       public.lf_v_request_overview_24h,
       public.lf_v_endpoint_analytics_24h,
       public.lf_v_backend_distribution_24h,
       public.lf_v_request_timeseries_15s,
       public.lf_v_security_summary_24h,
       public.lf_v_load_test_history,
       public.lf_v_latest_db_pool_samples
    to service_role;

do $$
declare
    item record;
begin
    for item in
        select
            p.oid::regprocedure as function_signature
        from pg_proc p
        join pg_namespace n
          on n.oid = p.pronamespace
        where n.nspname = 'public'
          and p.proname like 'lf\_%' escape '\'
    loop
        execute format(
            'grant execute on function %s to service_role',
            item.function_signature
        );
    end loop;
end;
$$;

commit;

